--
-- Name: contracts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE IF NOT EXISTS public.contracts (
    allowed_mileage integer,
    cleaning_fees numeric(10,2),
    client_birth_date date,
    client_driver_license_expiry date,
    client_driver_license_issue date,
    contract_duration integer,
    daily_price numeric(10,2),
    deleted boolean DEFAULT false,
    delivery_fees numeric(10,2),
    deposit_amount numeric(10,2),
    discount_amount numeric(10,2),
    end_date date NOT NULL,
    extra_hours integer,
    extra_mileage_cost numeric(10,2),
    fuel_charges numeric(10,2),
    insurance_expiration date,
    late_fees numeric(10,2),
    mileage_end integer,
    mileage_start integer,
    paid_amount numeric(10,2),
    payment_date date,
    pickup_date date,
    pickup_time time(6) without time zone,
    remaining_amount numeric(10,2),
    rental_days integer,
    return_date date,
    return_fees numeric(10,2),
    return_time time(6) without time zone,
    start_date date NOT NULL,
    tax_amount numeric(10,2),
    technical_inspection_expiration date,
    terms_accepted boolean,
    total_price numeric(10,2),
    vehicle_year integer,
    client_id bigint,
    client_signed_at timestamp(6) without time zone,
    created_at timestamp(6) without time zone,
    deleted_at timestamp(6) without time zone,
    id bigint NOT NULL,
    owner_signed_at timestamp(6) without time zone,
    reservation_id bigint,
    signed_at timestamp(6) without time zone,
    tenant_id bigint NOT NULL,
    terms_accepted_at timestamp(6) without time zone,
    updated_at timestamp(6) without time zone,
    vehicle_id bigint,
    client_gender character varying(10),
    contract_language character varying(10),
    deposit_currency character varying(10),
    client_postal_code character varying(20),
    fuel_level_end character varying(20),
    fuel_level_start character varying(20),
    fuel_type character varying(20),
    payment_status character varying(20),
    vehicle_transmission character varying(20),
    contract_status character varying(30) NOT NULL,
    contract_type character varying(30),
    payment_method character varying(30),
    status_before_delete character varying(30),
    vehicle_color character varying(30),
    client_cin character varying(50),
    client_driver_license character varying(50),
    client_nationality character varying(50),
    client_passport_number character varying(50),
    client_phone character varying(50),
    client_secondary_phone character varying(50),
    client_signed_ip character varying(50),
    contract_number character varying(50) NOT NULL,
    deposit_status character varying(50),
    emergency_contact_phone character varying(50),
    invoice_number character varying(50),
    owner_signed_ip character varying(50),
    previous_reservation_status character varying(50),
    vehicle_category character varying(50),
    vehicle_registration character varying(50),
    vehicle_vin character varying(50),
    client_city character varying(100),
    client_country character varying(100),
    client_first_name character varying(100),
    client_last_name character varying(100),
    insurance_provider character varying(100),
    vehicle_brand character varying(100),
    vehicle_model character varying(100),
    qr_token character varying(128),
    client_email character varying(150),
    deleted_by character varying(150),
    emergency_contact_name character varying(150),
    generated_by character varying(150),
    last_modified_by character varying(150),
    pickup_agency character varying(150),
    pickup_agent character varying(150),
    return_agency character varying(150),
    return_agent character varying(150),
    client_full_name character varying(200),
    client_name character varying(200),
    pdf_url character varying(512),
    public_signing_url character varying(512),
    branding_logo_url text,
    branding_stamp_url text,
    branding_terms_snapshot text,
    client_address character varying(255),
    client_signature text,
    client_user_agent character varying(255),
    condition_end_note text,
    condition_start_note text,
    damage_end_note text,
    damage_start_note text,
    employee_signature text,
    notes text,
    owner_signature text,
    owner_user_agent character varying(255),
    pickup_location character varying(255),
    return_location character varying(255),
    CONSTRAINT contracts_contract_status_check CHECK (((contract_status)::text = ANY ((ARRAY['DRAFT'::character varying, 'WAITING_SIGNATURE'::character varying, 'WAITING_CLIENT_SIGNATURE'::character varying, 'PENDING_SIGNATURE'::character varying, 'PARTIALLY_SIGNED'::character varying, 'SIGNED'::character varying, 'ACTIVE'::character varying, 'PAID'::character varying, 'COMPLETED'::character varying, 'CANCELLED'::character varying, 'EXPIRED'::character varying])::text[]))),
    CONSTRAINT contracts_deposit_status_check CHECK (((deposit_status)::text = ANY ((ARRAY['NOT_REQUIRED'::character varying, 'PENDING'::character varying, 'RECEIVED'::character varying, 'HELD'::character varying, 'PARTIALLY_RETURNED'::character varying, 'RETURNED'::character varying, 'KEPT'::character varying, 'DEDUCTED'::character varying, 'CANCELLED'::character varying])::text[]))),
    CONSTRAINT contracts_status_before_delete_check CHECK (((status_before_delete)::text = ANY ((ARRAY['DRAFT'::character varying, 'WAITING_SIGNATURE'::character varying, 'WAITING_CLIENT_SIGNATURE'::character varying, 'PENDING_SIGNATURE'::character varying, 'PARTIALLY_SIGNED'::character varying, 'SIGNED'::character varying, 'ACTIVE'::character varying, 'PAID'::character varying, 'COMPLETED'::character varying, 'CANCELLED'::character varying, 'EXPIRED'::character varying])::text[])))
);

