    CONSTRAINT vehicles_statut_check CHECK (((statut)::text = ANY ((ARRAY['AVAILABLE'::character varying, 'RESERVED'::character varying, 'RENTED'::character varying, 'IN_MAINTENANCE'::character varying, 'OUT_OF_SERVICE'::character varying, 'SOLD'::character varying, 'ARCHIVED'::character varying, 'MAINTENANCE'::character varying])::text[])))
);

